$action='__cli__'; require_once __DIR__ . '/../../../configs/connectDB.php'; $user=['id'=>0]; require_once __DIR__ . '/../../api/warehouse/warehouse_sync_actions.php';
function pl_args(array $argv): array{$r=[];foreach($argv as $a){if(!is_string($a)||!str_starts_with($a,'--'))continue;$p=strpos($a,'=');$p===false?$r[substr($a,2)]='1':$r[substr($a,2,$p-2)]=substr($a,$p+1);}return$r;}
function pl_out(array $p,int $c=0): void{echo json_encode($p,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES|JSON_PRETTY_PRINT).PHP_EOL;exit($c);} 
function pl_norm(string $v): string{$v=trim($v);if(strlen($v)>=2&&(($v[0]==='"'&&substr($v,-1)==='"')||($v[0]==="'"&&substr($v,-1)==="'")))$v=substr($v,1,-1);return trim($v);} 
function pl_cols(mysqli $db,string $t): array{$c=[];if($r=$db->query('SHOW COLUMNS FROM `'.str_replace('`','``',$t).'`')){while($row=$r->fetch_assoc())$c[strtolower($row['Field'])]=1;$r->free();}return$c;}
function pl_ensure(mysqli $db): void{warehouse_sync_ensure_out_table($db);$cols=pl_cols($db,'warehouse_item_out');$adds=['label_payload_status'=>'ALTER TABLE warehouse_item_out ADD COLUMN label_payload_status VARCHAR(32) NULL','label_payload_message'=>'ALTER TABLE warehouse_item_out ADD COLUMN label_payload_message TEXT NULL','label_payload_json'=>'ALTER TABLE warehouse_item_out ADD COLUMN label_payload_json LONGTEXT NULL','label_payload_synced_at'=>'ALTER TABLE warehouse_item_out ADD COLUMN label_payload_synced_at DATETIME NULL','label_payload_source'=>'ALTER TABLE warehouse_item_out ADD COLUMN label_payload_source VARCHAR(64) NULL'];foreach($adds as$c=>$sql)if(!isset($cols[$c]))@$db->query($sql);@$db->query('ALTER TABLE warehouse_item_out ADD INDEX idx_wio_label_payload_status (label_payload_status)');}
function pl_report(mysqli $db,string $track): array{$track=pl_norm($track);foreach(['connector_report_colibri_az','forwarder_report_items'] as $t){$cols=pl_cols($db,$t);if(!$cols||!isset($cols['payload_json']))continue;$sql='SELECT payload_json FROM `'.str_replace('`','``',$t).'` WHERE payload_json LIKE ? ORDER BY id DESC LIMIT 1';$like='%'.$track.'%';$s=$db->prepare($sql);if(!$s)continue;$s->bind_param('s',$like);$s->execute();$row=$s->get_result()?->fetch_assoc();$s->close();$p=$row?json_decode((string)$row['payload_json'],true):null;if(is_array($p))return$p;}return[];}
function pl_client(mysqli $db,int $cid,string $clientId): array{if($clientId==='')return[];$s=$db->prepare('SELECT * FROM connector_clients WHERE connector_id=? AND client_id=? LIMIT 1');if(!$s)return[];$s->bind_param('is',$cid,$clientId);$s->execute();$r=$s->get_result()?->fetch_assoc()?:[];$s->close();return$r;}
function pl_val(array $a,string ...$ks): string{foreach($ks as$k){$v=trim((string)($a[$k]??''));if($v!=='')return pl_norm($v);}return'';}
function pl_bad(array $p): bool{$bad=['Test Client','Baku, Test street','TEST-TRACK','INT-00001','CLI001'];$j=json_encode($p,JSON_UNESCAPED_UNICODE);foreach($bad as$b)if(stripos((string)$j,$b)!==false)return true;return false;}
function pl_missing(array $p): array{$m=[];foreach(['tracking_no','client_name','client_address','category'] as$k)if(trim((string)($p[$k]??''))==='')$m[]=$k;if(trim((string)($p['internal_id']??$p['cbr_number']??''))==='')$m[]='internal_id';if(trim((string)($p['gross_weight']??$p['weight']??''))==='')$m[]='weight';if(trim((string)($p['invoice']??$p['amount']??''))==='')$m[]='invoice';if(trim((string)($p['currency']??''))==='' && !preg_match('/\b[A-Z]{3}\b/',(string)($p['amount']??'')))$m[]='currency';return$m;}
function pl_details(int $cid,string $track): array{$script=__DIR__.'/../mvp/app/Forwarder/run_package_details.php';$cmd='php '.escapeshellarg($script).' --connector-id='.escapeshellarg((string)$cid).' --track='.escapeshellarg($track).' 2>&1';$lines=[];$code=0;@exec($cmd,$lines,$code);$out=implode("\n",$lines);$j=json_decode($out,true);return is_array($j)?$j:['status'=>'error','message'=>$out,'exit_code'=>$code];}
try{global $dbcnx;if(!$dbcnx instanceof mysqli)throw new RuntimeException('DB unavailable');$dbcnx->set_charset('utf8mb4');pl_ensure($dbcnx);$a=pl_args($argv);$limit=max(1,min(500,(int)($a['limit']??100)));$cid=(int)($a['connector-id']??$a['connector_id']??0);$track=pl_norm((string)($a['track']??''));$where="wo.status='to_send' AND (wo.label_payload_status IS NULL OR wo.label_payload_status IN ('partial','error','stale'))";if($track!=='')$where.=" AND (wo.tracking_no='".$dbcnx->real_escape_string($track)."' OR wo.tuid='".$dbcnx->real_escape_string($track)."')";$sql="SELECT wo.*,wi.receiver_company,wi.receiver_country_code FROM warehouse_item_out wo LEFT JOIN warehouse_item_stock wi ON wi.id=wo.stock_item_id WHERE $where ORDER BY wo.id ASC LIMIT $limit";$rows=$dbcnx->query($sql)?->fetch_all(MYSQLI_ASSOC)?:[];$ok=0;$partial=0;$err=0;foreach($rows as$item){$outId=(int)$item['id'];try{$connector=warehouse_sync_resolve_permitted_connector($dbcnx,$item,$cid);$connectorId=(int)$connector['id'];$tr=pl_norm((string)($item['tracking_no']?:$item['tuid']));$rep=pl_report($dbcnx,$tr);$clientId=pl_val($rep,'client_id');$client=pl_client($dbcnx,$connectorId,$clientId);$pkg=[];$source='report+cache';$payload=['track'=>$tr,'tracking_no'=>$tr,'internal_id'=>pl_val($rep,'internal_id','cbr_number'),'cbr_number'=>pl_val($rep,'cbr_number','internal_id'),'client_id'=>$clientId,'client_code'=>$clientId!==''?'C'.$clientId:'','client_name'=>pl_val($client,'client_name')?:pl_val($rep,'client_name'),'client_phone'=>pl_val($client,'client_phone'),'consignee_phone'=>pl_val($client,'client_phone'),'client_address'=>pl_val($client,'client_address'),'category'=>pl_val($rep,'category'),'seller'=>pl_val($rep,'seller'),'invoice'=>pl_val($rep,'invoice_price','invoice'),'currency'=>pl_val($rep,'currency'),'gross_weight'=>pl_val($rep,'weight','gross_weight'),'weight'=>pl_val($rep,'weight','gross_weight'),'country_dest'=>'Azerbaijan','receiver_country_code'=>'AZ','forward_name'=>trim((string)($connector['name']??'COLIBRI')),'report_status'=>pl_val($rep,'status'),'forwarder_storage'=>pl_val($rep,'storage'),'source'=>$source];$payload['barcode_value']=$payload['internal_id']?:$payload['cbr_number'];$miss=pl_missing($payload);if($miss){$d=pl_details($connectorId,$tr);if(($d['status']??'')==='ok'&&is_array($d['package']??null)){$pkg=$d['package'];$source='report+check-package';foreach(['internal_id','cbr_number','barcode_value'] as$k){$payload[$k]=$payload[$k]?:pl_val($pkg,'internal_id');}$map=['client_id'=>'client_id','client_code'=>'client_code','client_name'=>'client_name','client_phone'=>'client_phone','consignee_phone'=>'client_phone','client_address'=>'client_address','category'=>'category','seller'=>'seller','invoice'=>'invoice','invoice_usd'=>'invoice_usd','currency'=>'currency','amount'=>'amount','gross_weight'=>'gross_weight','weight'=>'gross_weight','volume_weight'=>'volume_weight','invoice_doc'=>'invoice_doc'];foreach($map as$k=>$pk){$payload[$k]=pl_val($payload,$k)?:pl_val($pkg,$pk);} $payload['source']=$source;$miss=pl_missing($payload);} }
if(pl_bad($payload)){$status='error';$msg='forbidden test payload values';$err++;}elseif(!$miss){$status='ready';$msg='ready';$ok++;}else{$status='partial';$msg='missing: '.implode(', ',$miss);$partial++;}$json=json_encode($payload,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES);$s=$dbcnx->prepare('UPDATE warehouse_item_out SET label_payload_status=?,label_payload_message=?,label_payload_json=?,label_payload_synced_at=NOW(),label_payload_source=? WHERE id=?');$s->bind_param('ssssi',$status,$msg,$json,$source,$outId);$s->execute();$s->close();}catch(Throwable$e){$msg=$e->getMessage();$s=$dbcnx->prepare("UPDATE warehouse_item_out SET label_payload_status='error',label_payload_message=?,label_payload_synced_at=NOW() WHERE id=?");$s->bind_param('si',$msg,$outId);$s->execute();$s->close();$err++;}}pl_out(['status'=>'ok','processed'=>count($rows),'ready'=>$ok,'partial'=>$partial,'errors'=>$err]);}catch(Throwable$e){pl_out(['status'=>'error','message'=>$e->getMessage()],1);} 
